// FizzBuzz Verifier — runs the candidate's solution.js and prints JSON on last line
const fs = require('fs');
const path = require('path');

function runVerifier() {
  const solutionPath = path.join(__dirname, 'solution.js');
  if (!fs.existsSync(solutionPath)) {
    console.log(JSON.stringify({ passed: false, score: 0, summary: 'solution.js not found', details: { error: 'missing file' } }));
    process.exit(1);
  }

  // Capture console.log output from the solution
  const logs = [];
  const origLog = console.log;
  console.log = (...args) => { logs.push(args.map(String).join(' ')); };

  try {
    require(solutionPath);
  } catch (e) {
    console.log = origLog;
    console.log(JSON.stringify({ passed: false, score: 0, summary: 'Solution threw an error: ' + e.message, details: { error: e.message } }));
    process.exit(1);
  }

  console.log = origLog;

  // Verify FizzBuzz output
  const lines = logs.flatMap(l => l.split('\n')).filter(l => l.trim());
  let passed = true;
  let score = 10;
  const details = [];

  if (lines.length !== 100) {
    passed = false;
    score = 0;
    details.push('Expected 100 lines, got ' + lines.length);
  }

  for (let i = 1; i <= 100 && passed; i++) {
    const line = lines[i - 1];
    let expected;
    if (i % 15 === 0) expected = 'FizzBuzz';
    else if (i % 3 === 0) expected = 'Fizz';
    else if (i % 5 === 0) expected = 'Buzz';
    else expected = String(i);

    if (line !== expected) {
      passed = false;
      score = Math.max(0, score - 3);
      details.push('Line ' + i + ': expected "' + expected + '", got "' + line + '"');
      if (details.length >= 3) break;
    }
  }

  if (passed) {
    details.push('All 100 lines correct');
  }

  const summary = passed ? 'All FizzBuzz tests passed!' : 'Some tests failed. See details.';
  console.log(JSON.stringify({ passed, score, summary, details }));
}

runVerifier();
